// AI content generation — newsletter drafts + event recaps
// prototype-schedule: "0 9 * * 1" (requires hobby tier — prototype allows only 1 scheduled fn)
import { db } from 'run402-functions';

export default async (req) => {
  // Route: if request has event_id body, handle recap; otherwise handle newsletter
  let body = {};
  try {
    body = await req.json();
  } catch {}

  if (body.event_id) {
    return handleRecap(body.event_id);
  }
  return handleNewsletter();
};

// --- Newsletter ---

async function handleNewsletter() {
  const flag = await db.from('site_config').select('value').eq('key', 'feature_ai_newsletter').limit(1);
  if (!flag.length || (flag[0].value !== true && flag[0].value !== 'true')) {
    return new Response(JSON.stringify({ status: 'skipped', reason: 'feature_ai_newsletter disabled' }));
  }

  if (!process.env.AI_API_KEY) {
    return new Response(JSON.stringify({ status: 'skipped', reason: 'AI_API_KEY not set' }));
  }

  const provider = process.env.AI_PROVIDER || 'openai';
  const now = new Date();
  const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
  const weekAgoISO = weekAgo.toISOString();

  const activity = await gatherWeeklyActivity(weekAgoISO);

  if (!activity.hasContent) {
    return new Response(JSON.stringify({ status: 'skipped', reason: 'no activity in the past week' }));
  }

  const siteName = await getSiteName();

  try {
    const newsletter = await generateNewsletter(provider, siteName, activity);

    await db.from('newsletter_drafts').insert({
      subject: newsletter.subject,
      body: newsletter.body,
      status: 'draft',
      period_start: weekAgoISO,
      period_end: now.toISOString(),
    });

    return new Response(JSON.stringify({ status: 'ok', subject: newsletter.subject }));
  } catch (e) {
    console.error('Newsletter generation failed:', e.message);
    return new Response(JSON.stringify({ status: 'error', error: e.message }), { status: 500 });
  }
}

async function gatherWeeklyActivity(since) {
  const [newMembers, upcomingEvents, announcements, topForumPosts, newResources] = await Promise.all([
    db.from('members').select('display_name').gte('joined_at', since).eq('status', 'active'),
    db
      .from('events')
      .select('title,starts_at,location')
      .gte('starts_at', new Date().toISOString())
      .order('starts_at', { ascending: true })
      .limit(5),
    db
      .from('announcements')
      .select('title,body')
      .gte('created_at', since)
      .order('created_at', { ascending: false })
      .limit(5),
    db
      .from('forum_topics')
      .select('title,reply_count')
      .gte('created_at', since)
      .order('reply_count', { ascending: false })
      .limit(5),
    db.from('resources').select('title,category').gte('created_at', since).limit(5),
  ]);

  const hasContent =
    newMembers.length > 0 ||
    upcomingEvents.length > 0 ||
    announcements.length > 0 ||
    topForumPosts.length > 0 ||
    newResources.length > 0;

  return { newMembers, upcomingEvents, announcements, topForumPosts, newResources, hasContent };
}

async function generateNewsletter(provider, siteName, activity) {
  const sections = [];
  if (activity.newMembers.length > 0) {
    sections.push(`New members this week: ${activity.newMembers.map((m) => m.display_name).join(', ')}`);
  }
  if (activity.upcomingEvents.length > 0) {
    sections.push(
      'Upcoming events:\n' +
        activity.upcomingEvents
          .map(
            (e) =>
              `- ${e.title} on ${new Date(e.starts_at).toLocaleDateString()}${e.location ? ` at ${e.location}` : ''}`,
          )
          .join('\n'),
    );
  }
  if (activity.announcements.length > 0) {
    sections.push(`Recent announcements:\n${activity.announcements.map((a) => `- ${a.title}`).join('\n')}`);
  }
  if (activity.topForumPosts.length > 0) {
    sections.push(
      'Popular discussions:\n' +
        activity.topForumPosts.map((p) => `- ${p.title} (${p.reply_count} replies)`).join('\n'),
    );
  }
  if (activity.newResources.length > 0) {
    sections.push(
      'New resources:\n' +
        activity.newResources.map((r) => `- ${r.title}${r.category ? ` (${r.category})` : ''}`).join('\n'),
    );
  }

  const prompt = `Write a friendly, concise weekly newsletter for "${siteName}". Output JSON with "subject" and "body" (HTML). The body should be warm, use <h2>, <p>, <ul> tags, and be ready to send.

Community activity this week:
${sections.join('\n\n')}`;

  const response = await callAI(provider, prompt, 2048);
  const jsonMatch = response.match(/\{[\s\S]*\}/);
  const parsed = JSON.parse(jsonMatch ? jsonMatch[0] : response);

  return {
    subject: parsed.subject || `${siteName} — Weekly Update`,
    body: parsed.body || '<p>This week in our community...</p>',
  };
}

// --- Event Recap ---

async function handleRecap(eventId) {
  const flag = await db.from('site_config').select('value').eq('key', 'feature_ai_event_recaps').limit(1);
  if (!flag.length || (flag[0].value !== true && flag[0].value !== 'true')) {
    return new Response(JSON.stringify({ error: 'feature_ai_event_recaps disabled' }), { status: 403 });
  }

  if (!process.env.AI_API_KEY) {
    return new Response(JSON.stringify({ error: 'AI_API_KEY not set' }), { status: 500 });
  }

  const events = await db.from('events').select('id,title,description,starts_at,ends_at,location').eq('id', eventId);
  if (!events.length) {
    return new Response(JSON.stringify({ error: 'Event not found' }), { status: 404 });
  }
  const event = events[0];

  const endsAt = event.ends_at || event.starts_at;
  if (new Date(endsAt) > new Date()) {
    return new Response(JSON.stringify({ error: 'Event has not ended yet' }), { status: 400 });
  }

  const rsvps = await db.from('event_rsvps').select('id').eq('event_id', eventId).eq('status', 'going');
  const attendeeCount = rsvps.length;
  const siteName = await getSiteName();
  const provider = process.env.AI_PROVIDER || 'openai';

  try {
    const eventDate = new Date(event.starts_at).toLocaleDateString(undefined, {
      weekday: 'long',
      month: 'long',
      day: 'numeric',
    });
    const prompt = `Write a brief, warm event recap for "${siteName}". Output JSON with "title" and "body" (HTML with <p> tags).

Event: ${event.title}
Date: ${eventDate}
Location: ${event.location || 'Not specified'}
Attendees: ${attendeeCount}
Description: ${(event.description || '').substring(0, 500)}`;

    const response = await callAI(provider, prompt, 1024);
    const jsonMatch = response.match(/\{[\s\S]*\}/);
    const parsed = JSON.parse(jsonMatch ? jsonMatch[0] : response);

    const recap = {
      title: parsed.title || `Recap: ${event.title}`,
      body: parsed.body || `<p>Thanks to everyone who attended ${event.title}!</p>`,
    };

    await db.from('announcements').insert({
      title: recap.title,
      body: recap.body,
      is_pinned: false,
    });

    return new Response(JSON.stringify({ status: 'ok', title: recap.title }));
  } catch (e) {
    console.error('Recap generation failed:', e.message);
    return new Response(JSON.stringify({ error: e.message }), { status: 500 });
  }
}

// --- Shared helpers ---

async function getSiteName() {
  const nameRow = await db.from('site_config').select('value').eq('key', 'site_name').limit(1);
  return nameRow.length ? JSON.parse(JSON.stringify(nameRow[0].value)).replace(/^"|"$/g, '') : 'Our Community';
}

async function callAI(provider, prompt, maxTokens) {
  if (provider === 'anthropic') {
    const res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': process.env.AI_API_KEY,
        'content-type': 'application/json',
        'anthropic-version': '2023-06-01',
      },
      body: JSON.stringify({
        model: 'claude-haiku-4-5-20251001',
        max_tokens: maxTokens,
        messages: [{ role: 'user', content: prompt }],
      }),
    });
    const data = await res.json();
    return data.content?.[0]?.text || '{}';
  } else {
    const res = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${process.env.AI_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        messages: [{ role: 'user', content: prompt }],
        max_tokens: maxTokens,
      }),
    });
    const data = await res.json();
    return data.choices?.[0]?.message?.content || '{}';
  }
}

// prototype-schedule: "0 * * * *" (requires hobby tier — prototype allows only 1 scheduled fn)
import { db, email } from 'run402-functions';

export default async (_req) => {
  const now = new Date();
  const oneHourFromNow = new Date(now.getTime() + 60 * 60 * 1000);
  let sent = 0;

  // Find events starting within the next hour
  const events = await db
    .from('events')
    .select('id,title,starts_at,location')
    .gte('starts_at', now.toISOString())
    .lt('starts_at', oneHourFromNow.toISOString());

  for (const event of events) {
    // Get RSVPd members (going or maybe)
    const rsvps = await db.sql(`
      SELECT m.email, m.display_name FROM event_rsvps r
      JOIN members m ON m.id = r.member_id
      WHERE r.event_id = ${event.id} AND r.status IN ('going', 'maybe') AND m.email != ''
    `);
    const attendees = rsvps.rows || rsvps;

    for (const attendee of attendees) {
      if (!attendee.email) continue;
      try {
        const time = new Date(event.starts_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
        await email.send({
          to: attendee.email,
          subject: `Reminder: ${event.title} starts soon`,
          html: `<p>Hi ${attendee.display_name},</p><p><strong>${event.title}</strong> starts at ${time}${event.location ? ` at ${event.location}` : ''}.</p><p>See you there!</p>`,
          from_name: 'Wild Lychee Community',
        });
        sent++;
      } catch (e) {
        console.warn('Reminder email failed:', e.message);
      }
    }
  }

  return new Response(JSON.stringify({ status: 'ok', events_checked: events.length, reminders_sent: sent }));
};

// schedule: none (triggered manually from admin UI)
import { db, getUser } from 'run402-functions';

export default async (req) => {
  const user = await getUser(req);
  if (!user) {
    return new Response(JSON.stringify({ error: 'Unauthorized' }), { status: 401 });
  }

  const url = new URL(req.url);
  const type = url.searchParams.get('type') || 'members';

  let csv = '';

  if (type === 'members') {
    const result = await db.sql(`
      SELECT m.display_name, m.email, m.status, m.role, t.name as tier, m.joined_at, m.custom_fields
      FROM members m
      LEFT JOIN membership_tiers t ON t.id = m.tier_id
      ORDER BY m.created_at DESC
    `);
    const rows = result.rows || result;
    const headers = ['display_name', 'email', 'status', 'role', 'tier', 'joined_at', 'custom_fields'];
    csv = `${headers.join(',')}\n`;
    csv += rows
      .map((r) =>
        headers
          .map((h) => {
            const val = h === 'custom_fields' ? JSON.stringify(r[h] || {}) : String(r[h] || '');
            return `"${val.replace(/"/g, '""')}"`;
          })
          .join(','),
      )
      .join('\n');
  } else if (type === 'events') {
    const result = await db.sql(`
      SELECT e.title, e.starts_at, e.ends_at, e.location, e.capacity,
        (SELECT count(*) FROM event_rsvps r WHERE r.event_id = e.id AND r.status = 'going') as rsvp_count
      FROM events e
      ORDER BY e.starts_at DESC
    `);
    const rows = result.rows || result;
    const headers = ['title', 'starts_at', 'ends_at', 'location', 'capacity', 'rsvp_count'];
    csv = `${headers.join(',')}\n`;
    csv += rows.map((r) => headers.map((h) => `"${String(r[h] || '').replace(/"/g, '""')}"`).join(',')).join('\n');
  } else {
    return new Response(JSON.stringify({ error: 'Invalid type. Use members or events.' }), { status: 400 });
  }

  return new Response(csv, {
    headers: {
      'Content-Type': 'text/csv',
      'Content-Disposition': `attachment; filename="${type}-export.csv"`,
    },
  });
};

// prototype-schedule: "*/15 * * * *" (requires hobby tier — prototype allows only 1 scheduled fn)
import { ai, db } from 'run402-functions';

export default async (_req) => {
  // Check if feature is enabled
  const flag = await db.from('site_config').select('value').eq('key', 'feature_ai_moderation').limit(1);
  if (!flag.length || (flag[0].value !== true && flag[0].value !== 'true')) {
    return new Response(JSON.stringify({ status: 'skipped', reason: 'feature_ai_moderation disabled' }));
  }

  let moderated = 0;

  // Find last moderation timestamp
  const lastCheck = await db.sql('SELECT max(created_at) as last_at FROM moderation_log');
  const lastAt = (lastCheck.rows || lastCheck)[0]?.last_at || '1970-01-01T00:00:00Z';

  // Get new forum topics since last check
  const newTopics = await db
    .from('forum_topics')
    .select('id,title,body,author_id')
    .gt('created_at', lastAt)
    .eq('hidden', false);

  for (const topic of newTopics) {
    const result = await moderateContent(`${topic.title}\n\n${topic.body}`);
    if (result.confidence > 0.7 && result.flagged) {
      await db.from('forum_topics').update({ hidden: true }).eq('id', topic.id);
    }
    await db.from('moderation_log').insert({
      content_type: 'forum_topic',
      content_id: topic.id,
      action: result.action,
      reason: result.reason,
      confidence: result.confidence,
    });
    moderated++;
  }

  // Get new forum replies since last check
  const newReplies = await db
    .from('forum_replies')
    .select('id,body,author_id')
    .gt('created_at', lastAt)
    .eq('hidden', false);

  for (const reply of newReplies) {
    const result = await moderateContent(reply.body);
    if (result.confidence > 0.7 && result.flagged) {
      await db.from('forum_replies').update({ hidden: true }).eq('id', reply.id);
    }
    await db.from('moderation_log').insert({
      content_type: 'forum_reply',
      content_id: reply.id,
      action: result.action,
      reason: result.reason,
      confidence: result.confidence,
    });
    moderated++;
  }

  return new Response(JSON.stringify({ status: 'ok', moderated }));
};

async function moderateContent(text) {
  try {
    const result = await ai.moderate(text.substring(0, 10000));
    const scores = result.category_scores || {};
    const entries = Object.entries(scores);
    const maxEntry = entries.reduce((a, b) => (b[1] > a[1] ? b : a), ['unknown', 0]);
    const confidence = maxEntry[1];
    const reason = maxEntry[0];

    if (!result.flagged) {
      return { action: 'approved', confidence, reason, flagged: false };
    }
    if (confidence > 0.7) {
      return { action: 'hidden', confidence, reason, flagged: true };
    }
    return { action: 'flagged', confidence, reason, flagged: true };
  } catch (e) {
    console.warn('ai.moderate() failed:', e.message);
    return { action: 'approved', confidence: 0, reason: 'moderation unavailable', flagged: false };
  }
}

// Lifecycle hook: called automatically by Run402 after first signup (fire-and-forget).
// Also supports direct invocation with auth token for backward compatibility.
import { db, getUser } from 'run402-functions';

export default async (req) => {
  // Determine user identity from lifecycle hook payload or auth token
  let userId, memberEmail;

  const isLifecycleHook = req.headers.get('x-run402-trigger') === 'signup';

  if (isLifecycleHook) {
    // Lifecycle hook: user info in request body, no auth token
    const body = await req.json();
    userId = body.user?.id;
    memberEmail = body.user?.email || '';
    if (!userId) {
      return new Response(JSON.stringify({ error: 'Missing user.id in hook payload' }), { status: 400 });
    }
  } else {
    // Direct invocation: use auth token
    const user = await getUser(req);
    if (!user) {
      return new Response(JSON.stringify({ error: 'Unauthorized' }), { status: 401 });
    }
    userId = user.id;
    memberEmail = user.email || '';
    // Fallback: try request body for email
    if (!memberEmail) {
      try {
        const body = await req.json();
        memberEmail = body.email || '';
      } catch {}
    }
  }

  // Check if user already has a member record
  const existing = await db.from('members').select('id,role,status').eq('user_id', userId).limit(1);
  if (existing.length > 0) {
    return new Response(
      JSON.stringify({
        status: 'exists',
        member_id: existing[0].id,
        role: existing[0].role,
      }),
    );
  }

  // Get user details from auth endpoint (for display_name, avatar)
  let authUser = {};
  const token = req.headers.get('Authorization')?.replace('Bearer ', '');
  if (token) {
    try {
      const authRes = await fetch('https://api.run402.com/auth/v1/user', {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (authRes.ok) authUser = await authRes.json();
    } catch {}
  }

  if (!memberEmail) memberEmail = authUser.email || '';
  const displayName = authUser.display_name || (memberEmail ? memberEmail.split('@')[0] : 'Member');
  const avatarUrl = authUser.avatar_url || null;

  // Check if this is the first user (becomes admin)
  const countResult = await db.sql('SELECT count(*)::int as count FROM members');
  const isFirst = countResult.rows.length === 0 || countResult.rows[0].count === 0;

  const role = isFirst ? 'admin' : 'member';
  const memberStatus = isFirst ? 'active' : 'pending';

  // Get default tier
  const defaultTier = await db.from('membership_tiers').select('id').eq('is_default', true).limit(1);
  const tierId = defaultTier.length > 0 ? defaultTier[0].id : null;

  // Create member record
  const created = await db
    .from('members')
    .insert({
      user_id: userId,
      email: memberEmail,
      display_name: displayName,
      avatar_url: avatarUrl,
      tier_id: tierId,
      role,
      status: memberStatus,
    })
    .select('id,role,status');

  if (created.length === 0) {
    return new Response(JSON.stringify({ error: 'Failed to create member' }), { status: 500 });
  }

  const member = created[0];

  // Log activity
  await db.from('activity_log').insert({
    member_id: member.id,
    action: 'signup',
    metadata: { role, is_first: isFirst },
  });

  return new Response(
    JSON.stringify({
      status: 'created',
      member_id: member.id,
      role: member.role,
      member_status: member.status,
    }),
  );
};

// schedule: none (triggered by client after content publish)
import { ai, db, getUser } from 'run402-functions';

export default async (req) => {
  const user = await getUser(req);
  if (!user) {
    return new Response(JSON.stringify({ error: 'Unauthorized' }), { status: 401 });
  }

  // Check if feature is enabled
  const flag = await db.from('site_config').select('value').eq('key', 'feature_ai_translation').limit(1);
  if (!flag.length || (flag[0].value !== true && flag[0].value !== 'true')) {
    return new Response(JSON.stringify({ status: 'skipped', reason: 'feature_ai_translation disabled' }));
  }

  let body;
  try {
    body = await req.json();
  } catch {
    return new Response(JSON.stringify({ error: 'Invalid body' }), { status: 400 });
  }

  const { content_type, content_id } = body;
  if (!content_type || !content_id) {
    return new Response(JSON.stringify({ error: 'content_type and content_id required' }), { status: 400 });
  }

  // Read the content
  let content = {};
  if (content_type === 'announcement') {
    const rows = await db.from('announcements').select('title,body').eq('id', content_id).limit(1);
    if (rows.length > 0) content = rows[0];
  } else if (content_type === 'event') {
    const rows = await db.from('events').select('title,description').eq('id', content_id).limit(1);
    if (rows.length > 0) content = { title: rows[0].title, body: rows[0].description };
  } else if (content_type === 'page') {
    const rows = await db.from('pages').select('title,content').eq('id', content_id).limit(1);
    if (rows.length > 0) content = { title: rows[0].title, body: rows[0].content };
  }

  if (!content.title) {
    return new Response(JSON.stringify({ error: 'Content not found' }), { status: 404 });
  }

  const targetLangs = (body.languages || ['pt', 'es']).filter((l) => l !== 'en');
  let translated = 0;
  const context = `${content_type} on a community portal`;

  for (const lang of targetLangs) {
    for (const field of ['title', 'body']) {
      if (!content[field]) continue;
      try {
        const result = await ai.translate(content[field].substring(0, 10000), lang, { context });
        if (result.text) {
          // Upsert into content_translations
          const existing = await db
            .from('content_translations')
            .select('id')
            .eq('content_type', content_type)
            .eq('content_id', content_id)
            .eq('language', lang)
            .eq('field', field)
            .limit(1);

          if (existing.length > 0) {
            await db.from('content_translations').update({ translated_text: result.text }).eq('id', existing[0].id);
          } else {
            await db.from('content_translations').insert({
              content_type,
              content_id,
              language: lang,
              field,
              translated_text: result.text,
            });
          }
          translated++;
        }
      } catch (e) {
        console.warn(`Translation to ${lang} failed for ${field}:`, e.message);
        // Continue with next field — partial success is fine
      }
    }
  }

  return new Response(JSON.stringify({ status: translated > 0 ? 'ok' : 'skipped', translated }));
};

// On-demand text translation for user-generated content (Twitter-style "Translate" button)
// Caches results in content_translations table. Uses OpenAI API via OPENAI_API_KEY secret.
import { db } from 'run402-functions';

export default async (req) => {
  let body;
  try {
    body = await req.json();
  } catch {
    return new Response(JSON.stringify({ error: 'Invalid body' }), { status: 400 });
  }

  const { text, target_lang, content_type, content_id, field } = body;
  if (!text || !target_lang) {
    return new Response(JSON.stringify({ error: 'text and target_lang required' }), { status: 400 });
  }

  // Check cache first (if content_type/content_id/field provided)
  if (content_type && content_id && field) {
    try {
      const cached = await db
        .from('content_translations')
        .select('translated_text')
        .eq('content_type', content_type)
        .eq('content_id', content_id)
        .eq('language', target_lang)
        .eq('field', field)
        .limit(1);
      if (cached.length > 0) {
        return new Response(JSON.stringify({ translated: cached[0].translated_text, cached: true }));
      }
    } catch {
      // cache lookup failed, proceed to translate
    }
  }

  const apiKey = process.env.OPENAI_API_KEY;
  if (!apiKey) {
    return new Response(JSON.stringify({ error: 'OPENAI_API_KEY not configured' }), { status: 500 });
  }

  const trimmed = text.substring(0, 5000);
  const langNames = { en: 'English', es: 'Spanish', pt: 'Portuguese', fr: 'French', de: 'German' };
  const langName = langNames[target_lang] || target_lang;

  try {
    const res = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${apiKey}`,
      },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        messages: [
          {
            role: 'system',
            content: `Translate the following text to ${langName}. Return only the translation, no explanations. Preserve the original tone and meaning. This is a community forum post.`,
          },
          { role: 'user', content: trimmed },
        ],
        temperature: 0.3,
        max_tokens: 2000,
      }),
    });

    const data = await res.json();
    const translated = data.choices?.[0]?.message?.content?.trim();

    if (!translated) {
      return new Response(JSON.stringify({ error: 'No translation returned' }), { status: 500 });
    }

    // Store in cache (if content_type/content_id/field provided)
    if (content_type && content_id && field) {
      try {
        await db.from('content_translations').insert({
          content_type,
          content_id: Number(content_id),
          language: target_lang,
          field,
          translated_text: translated,
        });
      } catch {
        // cache write failed (maybe duplicate), not critical
      }
    }

    return new Response(JSON.stringify({ translated }));
  } catch (e) {
    return new Response(JSON.stringify({ error: 'Translation failed: ' + e.message }), { status: 500 });
  }
};

// schedule: none (triggered by client on resource upload)
import { db, getUser } from 'run402-functions';

export default async (req) => {
  const user = await getUser(req);
  if (!user) {
    return new Response(JSON.stringify({ error: 'Unauthorized' }), { status: 401 });
  }

  try {
    const formData = await req.formData();
    const file = formData.get('file');
    const metadataStr = formData.get('metadata');
    const metadata = JSON.parse(metadataStr || '{}');

    if (!file) {
      return new Response(JSON.stringify({ error: 'No file provided' }), { status: 400 });
    }

    // Upload file to Run402 storage
    const path = `resources/${Date.now()}_${file.name}`;
    const uploadRes = await fetch(`https://api.run402.com/storage/v1/upload/${path}`, {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${process.env.RUN402_SERVICE_KEY}`,
      },
      body: file,
    });

    if (!uploadRes.ok) {
      const err = await uploadRes.text();
      return new Response(JSON.stringify({ error: 'Upload failed', detail: err }), { status: 500 });
    }

    const uploadResult = await uploadRes.json();
    const fileUrl = uploadResult.url || `/storage/${path}`;

    // Insert resource row
    const created = await db.from('resources').insert({
      title: metadata.title || file.name,
      description: metadata.description || null,
      category: metadata.category || null,
      file_url: fileUrl,
      file_type: metadata.file_type || 'pdf',
      is_members_only: metadata.is_members_only !== false,
      uploaded_by: metadata.uploaded_by || null,
    });

    return new Response(JSON.stringify({ status: 'ok', resource: created[0] }));
  } catch (e) {
    return new Response(JSON.stringify({ error: e.message }), { status: 500 });
  }
};
